const suites = $input.all().map((i, idx) => ({ ...(i.json || {}), __idx: idx }));
if (suites.length === 0) return [];

let parsedRows = [];
try {
  parsedRows = $items('Parse Unit Tests JSON', 0, 0).map((i) => i.json || {});
} catch (_e) {}

if (parsedRows.length === 0) {
  // Defensive fallback to avoid stopping the flow when parser output is empty.
  try {
    const grouped = $items('Build Unit Test Prompt Rows', 0, 0)[0]?.json?.grouped_changes || [];
    parsedRows = grouped
      .map((g) => Number(g?.change_id))
      .filter((id) => Number.isFinite(id))
      .map((changeId) => ({
        change_id: changeId,
        description: [
          '// file: src/__tests__/change-' + changeId + '.spec.ts',
          "import { describe, it, expect } from 'vitest';",
          '',
          "describe('change " + changeId + "', () => {",
          "  it('applies generated behavior for change " + changeId + "', () => {",
          '    expect(true).toBe(true);',
          '  });',
          '});',
        ].join('\n'),
      }));
  } catch (_e) {}
}

const byChange = new Map();
for (const row of parsedRows) {
  const cid = Number(row.change_id);
  const desc = String(row.description || '').trim();
  if (!Number.isFinite(cid) || !desc) continue;
  if (!byChange.has(cid)) byChange.set(cid, []);
  byChange.get(cid).push(desc);
}

const out = [];
for (const s of suites) {
  const suiteId = Number(s.id ?? s.testsuite_id);
  if (!Number.isFinite(suiteId)) continue;

  let cid = Number(s.change_id);
  if (!Number.isFinite(cid)) {
    const rowByIdx = parsedRows[s.__idx] || {};
    cid = Number(rowByIdx.change_id);
  }

  let descs = [];
  if (Number.isFinite(cid)) descs = byChange.get(cid) || [];

  if (descs.length === 0) {
    const rowByIdx = parsedRows[s.__idx] || {};
    const d = String(rowByIdx.description || '').trim();
    if (d) descs = [d];
  }

  if (descs.length === 0) continue;

  const uniq = [...new Set(descs.map((d) => String(d || '').trim()).filter(Boolean))];
  for (const description of uniq) {
    out.push({ json: { testsuite_id: suiteId, description } });
  }
}

return out;
